// A/B: string-state parser (shipped) vs int-enum-state parser (generated by
// /tmp/make-parser-int.mjs). Verifies identical token output first, then
// benchmarks default mode on the 1 MB dataset.
//
//   npx nano-bench bench/parser-research/parser-state-compare.js
//
// Purpose: confirm the historical string<->int state representation choice does
// not matter for parse throughput in the REAL parser (the isolated dispatch
// micro-bench said it shouldn't; this proves it end-to-end).

import {jsonParser as jpStr} from '../../src/core/parser.js';
import {jsonParser as jpInt} from './parser-int.js';
import {none} from 'stream-chain/core';

const collect = (jp, opts, chunks) => {
  const f = jp(opts);
  const out = [];
  for (const c of chunks) {
    const r = f(c);
    if (r !== none) for (const t of r.values) out.push({name: t.name, value: t.value});
  }
  const r = f(none);
  if (r !== none) for (const t of r.values) out.push({name: t.name, value: t.value});
  return out;
};

// ---- correctness: identical tokens on edge cases + main data, incl. 1-char chunks ----
const edge = JSON.stringify({
  neg: -123,
  zero: 0,
  float: 3.14159,
  exp: 6.022e23,
  expNeg: 1.5e-10,
  expPlus: 2e+5,
  big: 9007199254740991,
  esc: 'tab\tnl\nquote\\"slash\\/back\\\\',
  uni: 'é\u{1f600}',
  bools: [true, false, null],
  empty: {},
  emptyArr: [],
  nested: {a: [{b: [1, 2, {c: 'd'}]}]},
  str: 'plain string value'
});

const MODES = [undefined, {packValues: true, streamValues: false}, {packValues: false, streamValues: true}];
const chunkings = [
  ['one chunk', s => [s]],
  ['1-char chunks', s => [...s]],
  ['3-char chunks', s => s.match(/.{1,3}/gs)]
];

let checks = 0;
for (const doc of [edge]) {
  for (const opts of MODES) {
    for (const [label, split] of chunkings) {
      const chunks = split(doc);
      const a = JSON.stringify(collect(jpStr, opts, chunks));
      const b = JSON.stringify(collect(jpInt, opts, chunks));
      if (a !== b) {
        console.error(`MISMATCH opts=${JSON.stringify(opts)} chunking=${label}`);
        console.error('str:', a.slice(0, 400));
        console.error('int:', b.slice(0, 400));
        throw new Error('int-state parser produced different tokens');
      }
      ++checks;
    }
  }
}

// ---- benchmark dataset (1 MB mixed) ----
const items = [];
for (let i = 0; i < 5000; ++i) {
  items.push({
    id: i,
    name: `item-${i}-${'x'.repeat(20)}`,
    active: i % 2 === 0,
    score: i * 1.5,
    ratio: i / 7,
    tags: ['alpha', 'beta', 'gamma'],
    nested: {x: i, y: i * 2, label: `nested-${i}`, deep: {a: i, b: i % 3 === 0}}
  });
}
const jsonData = JSON.stringify(items);
// also verify identical on the big doc (one chunk + 64k chunks)
for (const [label, split] of [['big one chunk', s => [s]], ['big 64k', s => s.match(/[\s\S]{1,65536}/g)]]) {
  const chunks = split(jsonData);
  if (JSON.stringify(collect(jpStr, undefined, chunks)) !== JSON.stringify(collect(jpInt, undefined, chunks)))
    throw new Error('int-state parser differs on big doc: ' + label);
  ++checks;
}
console.log(`[state-compare] ${checks} token-equality checks passed; benchmarking ${(Buffer.byteLength(jsonData) / 1e6).toFixed(3)} MB`);

let sink = 0;
const run = jp => {
  const f = jp();
  let r = f(jsonData);
  if (r !== none) {
    const v = r.values;
    for (let i = 0; i < v.length; ++i) sink += v[i].name.length;
  }
  r = f(none);
  if (r !== none) {
    const v = r.values;
    for (let i = 0; i < v.length; ++i) sink += v[i].name.length;
  }
};

export default {
  'string-state'(n) {
    for (let i = 0; i < n; ++i) run(jpStr);
  },
  'int-state'(n) {
    for (let i = 0; i < n; ++i) run(jpInt);
  }
};

export {sink};
